extends Enemy

# First concrete enemy: 80 % weak, 20 % strong. Idle 32–64 ticks.
# Per-type tunables (threat/recovery/idle/probability) live in `balance.json`
# under the `enemy_basic` section, accessed via the `Balance` autoload.


func _pick_attack(rng_: RandomNumberGenerator) -> StringName:
	return &"strong" if rng_.randf() < Balance.strong_probability else &"weak"


func _pick_idle_duration(rng_: RandomNumberGenerator) -> int:
	return rng_.randi_range(Balance.idle_min_ticks, Balance.idle_max_ticks)


func _threat_weak_ticks() -> int:
	return Balance.threat_weak_ticks


func _threat_strong_ticks() -> int:
	return Balance.threat_strong_ticks


func _recovery_weak_ticks() -> int:
	return Balance.recovery_weak_ticks


func _recovery_strong_ticks() -> int:
	return Balance.recovery_strong_ticks


func _exhausted_ticks() -> int:
	return Balance.exhausted_ticks

