input.command:
$paths = @(); 
$paths += Get-ChildItem -Path "C:\Program Files","C:\Program Files (x86)","$env:LOCALAPPDATA","$env:APPDATA" -Filter "Godot*.exe" -Recurse -ErrorAction SilentlyContinue -Depth 3 | Select-Object -ExpandProperty FullName;
$paths += (Get-Command godot,godot4,"Godot_v*" -ErrorAction SilentlyContinue | Select-Object -ExpandProperty Source);
if ($paths.Count -eq 0) { "NO_GODOT_FOUND" } else { $paths | Select-Object -Unique }
